var d = document;
function main() {
// add a global variable for the canvas
var c = d.getElementById("canvas1");
 
// adjust the size of the inner canvas to the actual size 
// of the outer canvas that wraps around it.
c.width = parseInt(getComputedStyle(d.getElementsByTagName("div")[0]).width);
c.height = parseInt(getComputedStyle(d.getElementsByTagName("div")[1]).height) - 37; 
 
var ctx = c.getContext('2d');
ctx.fillStyle="#ff0"; // fill with black background
ctx.fillRect(0,0,500,480);
 
var player = {
    x: parseInt(c.width/2), 
    y: 190 ,
    w: 36, h: 36,
    vx: 0, vy: 0 };
 
var frame = function() { 
    ctx.fillStyle="#ff0"; // reset the canvas to fill with black background
 
    // redraw the image
    ctx.drawImage(
        player, 
        player.x + (player.w /2), 
        player.y - ((Math.abs(player.vy)*4) * Math.sign(player.vy))
    );
 
    // add some motion
    var dt = 0.1;
    if (!(player.vx === undefined || isNaN(player.vx))) {
        player.x += (player.vx*dt);
        console.log(player);
        } 
    else {}

    if (!((player.vy === 35) && ((player.y + player.h/2)>=(c.height - player.h)))) { // stop motion at bottom of screen
        var dt = 0.1;
        if (!(player.vy === undefined || isNaN(player.vx))) {
            player.y -= (Math.abs(player.vy)*dt);
            }
        else {}
        }

    requestAnimationFrame(frame);
};
 
// start the main loop!
requestAnimationFrame(frame);
 
d.onkeydown = function (event) { 
    if (event.key === 'a') 
        player.vx -= 2;
 
    else if (event.key ==="d")
        player.vx += 2;
 
    else if ((event.key==="w") && ((player.vy<0)||(player.y>=190))) // stop vertical velocity after bouncing, but allow it to keep going upwards (e.g. when moving down)
        {
        var dt = 0.3;
            player.vy -= Math.abs(Math.sign(player.vy)*dt);
        }
    
    else if ((event.key==="s") && ((player.y + player.h/2)<=(c.height - player.h))) 
        var dt = 0.15;
        {
            player.vy += Math.abs(Math.sign(player.vy)*dt);
        }
};
 
d.onkeyup= function (event) { 
    if ((event.key === 'a')||(event.key==='d')) 
        player.vx = 0 ;
    else {}

    var dt = 2; // slow down vertical velocity
        if (((player.vy>=35 && Math.sign(player.vy)==1)) || (player.y<=46) || ((Math.abs(player.vy))<dt)){
            player.vy -= dt*Math.sign(player.vy);
        }
};
}
main();

